sql:
SELECT resale_value 
FROM car_resale_values 
WHERE car_id = 1;

SELECT AVG(login_attempts_per_user) AS average_login_attempts
FROM (
  SELECT user_id, COUNT(*) AS login_attempts_per_user
  FROM login_attempts
  GROUP BY user_id
) AS login_summary;

SELECT MAX(created_at) AS latest_reset_token_created_at
FROM reset_password_tokens
WHERE user_id = 1;

SELECT COUNT(*) AS total_reset_password_requests
FROM reset_password_tokens
WHERE user_id = 1;

external_knowledge:
- "active since the beginning of 2023" refers to cars created after January 1, 2023, and updated before June 30, 2023; 
- "highest mileage cars" refers to the cars with the highest mileage within each user group; 
- "multiple successful logins" refers to users with more than three successful logins between January 1, 2023, and June 30, 2023; 
- "still have valid reset password tokens" refers to users with reset password tokens that have not expired (`expires_at > '2023-06-30'`).
